mapper.select:
select stat_id, stat_date, stat_type, customer_id, sales_user_id,
       order_count, total_amount, paid_amount, unpaid_amount, create_time
from oms_order_statistics

    and stat_type = #{statType}
    and stat_date = #{statDate}
    and customer_id = #{customerId}
    and sales_user_id = #{salesUserId}

order by stat_date desc
